sys_script_include.script:
var api_dtech_common = Class.create();
api_dtech_common.CONST_DTECH_TASK_TABLE_NAME = "x_153465_discovert_route_task_instance";
api_dtech_common.CONST_DTECH_TEMPLATE_TABLE_NAME = "x_153465_discovert_discover_routing_template";
api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME = "x_153465_discovert_route_tasks";
api_dtech_common.CONST_DTECH_REQUEST_TABLE_NAME = "x_153465_discovert_tasker_requests";

api_dtech_common.CONST_DTECH_TASK_TITLE_FIELD = "task_name";
api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TITLE_FIELD = "short_description";

api_dtech_common.prototype = {
	initialize: function() {
		this.grUtil = new global.GlideRecordUtil();

	},

	loadObject: function(gr_object, fieldArray){
		var taskerObject = {};
		var fields = this.grUtil.getFields(gr_object);
		for (var i=0; i < fieldArray.length; i++) {
			var fieldName =  fieldArray[i];

			var field = fields.filter(function (val){
				if(val == fieldName){
					return val;
				}
			});
			// field was found in the record
			if(field.length>0){
				taskerObject[fieldName] = this._getFieldObject(gr_object, fieldName);					
			}
		}
		return taskerObject;
	},

	_getFieldObject: function(gr_object, fieldName){
		var fieldObject = {};
		fieldObject.label = gr_object[fieldName].getLabel();

		fieldObject.value = gr_object.getValue(fieldName);
		fieldObject.display_value = gr_object.getDisplayValue(fieldName);

		// get the field type don't need this yet, but if we need type at some point we could use this
		// I took it out as it would pull this on every call when it doesn't change
		// var glideElement = gr_object.getElement(fieldName);
		// var descriptor = glideElement.getED();
		// var internalType = descriptor.getInternalType();
		// fieldObject.internal_type = internalType;		
		return fieldObject;
	},
	type: 'api_dtech_common'
};
